@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:where(.dark, .dark *));

@theme {
  --color-bg:           oklch(98.5% 0.008 80);
  --color-sidebar:      oklch(97.5% 0.008 80);
  --color-card:         #ffffff;
  --color-border:       oklch(92% 0.012 70);
  --color-ink:          oklch(22% 0.02 60);
  --color-ink-muted:    oklch(48% 0.015 60);
  --color-accent:       oklch(40% 0.09 35);
  --color-accent-fg:    oklch(98% 0.005 70);

  /* MCP Panorama: status + layer tints (light theme) */
  --color-status-released:    oklch(58% 0.14 155);
  --color-status-released-bg: oklch(95% 0.035 155);
  --color-status-dev:         oklch(68% 0.16 65);
  --color-status-dev-bg:      oklch(96% 0.04 80);
  --color-status-none:        oklch(62% 0.012 60);
  --color-status-none-bg:     oklch(96.5% 0.008 70);
  --color-layer-industry:     oklch(48% 0.09 240);
  --color-layer-industry-bg:  oklch(94% 0.025 240);
  --color-layer-public:       oklch(40% 0.09 35);
  --color-layer-public-bg:    oklch(94% 0.025 70);

  --font-sans:    "Inter", ui-sans-serif, system-ui;
  --font-serif:   "Fraunces", Georgia, serif;
  --font-mono:    "JetBrains Mono", ui-monospace, monospace;
  --radius-card:  10px;
}

.dark {
  --color-bg:           oklch(14% 0.006 240);
  --color-sidebar:      oklch(12% 0.005 240);
  --color-card:         oklch(19% 0.008 240);
  --color-border:       oklch(24% 0.008 240);
  --color-ink:          oklch(90% 0.006 240);
  --color-ink-muted:    oklch(58% 0.008 240);
  --color-accent:       oklch(72% 0.18 200);
  --color-accent-fg:    oklch(12% 0.01 240);

  /* MCP Panorama: surface-tinted backgrounds + lifted foregrounds for dark contrast */
  --color-status-released:    oklch(72% 0.14 155);
  --color-status-released-bg: oklch(22% 0.04 155);
  --color-status-dev:         oklch(78% 0.14 65);
  --color-status-dev-bg:      oklch(22% 0.04 65);
  --color-status-none:        oklch(70% 0.012 240);
  --color-status-none-bg:     oklch(20% 0.008 240);
  --color-layer-industry:     oklch(75% 0.12 240);
  --color-layer-industry-bg:  oklch(22% 0.04 240);
  --color-layer-public:       oklch(72% 0.18 200);
  --color-layer-public-bg:    oklch(22% 0.04 70);
}

.mono {
  --color-bg:           oklch(96% 0 0);
  --color-sidebar:      oklch(98% 0 0);
  --color-card:         #ffffff;
  --color-border:       oklch(88% 0 0);
  --color-ink:          oklch(14% 0 0);
  --color-ink-muted:    oklch(52% 0 0);
  --color-accent:       oklch(22% 0 0);
  --color-accent-fg:    #ffffff;

  /* MCP Panorama: pure-grey scale, no chroma */
  --color-status-released:    oklch(30% 0 0);
  --color-status-released-bg: oklch(92% 0 0);
  --color-status-dev:         oklch(45% 0 0);
  --color-status-dev-bg:      oklch(94% 0 0);
  --color-status-none:        oklch(60% 0 0);
  --color-status-none-bg:     oklch(96% 0 0);
  --color-layer-industry:     oklch(28% 0 0);
  --color-layer-industry-bg:  oklch(92% 0 0);
  --color-layer-public:       oklch(22% 0 0);
  --color-layer-public-bg:    oklch(90% 0 0);
}

@layer components {
  .badge-official { background: oklch(94% 0.025 70); color: oklch(35% 0.07 35); }
  .badge-popular  { background: oklch(94% 0.04 145); color: oklch(35% 0.12 145); }
  .badge-new      { background: oklch(95% 0.035 90); color: oklch(38% 0.13 70); }
  .dark .badge-official { background: oklch(22% 0.06 200); color: oklch(72% 0.18 200); }
  .dark .badge-popular  { background: oklch(22% 0.05 280); color: oklch(72% 0.16 280); }
  .dark .badge-new      { background: oklch(22% 0.05 50);  color: oklch(78% 0.16 50); }
  .mono .badge-official { background: oklch(20% 0 0); color: #ffffff; }
  .mono .badge-popular  { background: oklch(88% 0 0); color: oklch(22% 0 0); }
  .mono .badge-new      { background: oklch(92% 0 0); color: oklch(30% 0 0); }
}

// @vitest-environment nuxt
import { describe, expect, it } from "vitest"
import { mountSuspended } from "@nuxt/test-utils/runtime"
import { defineComponent } from "vue"
import ExtFeatureHero from "./ExtFeatureHero.vue"
import type { ExtensionListItem } from "~~/shared/db/queries-types"

const NuxtLinkStub = defineComponent({
  name: "NuxtLink",
  props: { to: { type: String, required: true } },
  template: "<a :href=\"to\"><slot /></a>",
})

const mountOpts = { global: { stubs: { NuxtLink: NuxtLinkStub } } }

function fixture(overrides: Partial<ExtensionListItem> = {}): ExtensionListItem {
  return {
    id: "ext-1",
    slug: "web-search",
    category: "skills",
    badge: null,
    scope: "personal",
    funcCat: null,
    subCat: null,
    l2: null,
    deptId: null,
    iconEmoji: "🔍",
    iconColor: "#5b8def",
    name: "Web Search",
    nameZh: null,
    tagline: "Find anything, fast.",
    taglineZh: null,
    description: "Search the web straight from your agent — no copy-paste detour.",
    descriptionZh: null,
    downloadsCount: 1248,
    starsAvg: "4.7",
    tagIds: [],
    ...overrides,
  }
}

describe("ExtFeatureHero", () => {
  it("renders the eyebrow, name, tagline, and description", async () => {
    const wrapper = await mountSuspended(ExtFeatureHero, {
      ...mountOpts,
      props: { extension: fixture() },
    })
    const text = wrapper.text()
    expect(text).toContain("Featured this week")
    expect(text).toContain("Web Search")
    expect(text).toContain("Find anything, fast.")
    expect(text).toContain("Search the web straight from your agent")
  })

  it("renders the install command line with the extension slug", async () => {
    const wrapper = await mountSuspended(ExtFeatureHero, {
      ...mountOpts,
      props: { extension: fixture({ slug: "kubernetes-helper" }) },
    })
    expect(wrapper.text()).toContain("agentcenter install kubernetes-helper")
  })

  it("links to the locale-prefixed detail page", async () => {
    const wrapper = await mountSuspended(ExtFeatureHero, {
      ...mountOpts,
      props: { extension: fixture({ slug: "web-search" }) },
    })
    const hrefs = wrapper.findAll("a").map((a) => a.attributes("href") ?? "")
    // Locale URLs are always prefixed (CLAUDE.md locked decision #5).
    expect(hrefs.some((href) => /^\/(en|zh)\/extensions\/web-search$/.test(href))).toBe(true)
  })

  it("omits the tagline paragraph when tagline is null", async () => {
    const wrapper = await mountSuspended(ExtFeatureHero, {
      ...mountOpts,
      props: { extension: fixture({ tagline: null }) },
    })
    // The tagline element uses font-serif italic — check it's not rendered.
    expect(wrapper.find("p.italic").exists()).toBe(false)
  })

  it("omits the description paragraph when description is null", async () => {
    const wrapper = await mountSuspended(ExtFeatureHero, {
      ...mountOpts,
      props: { extension: fixture({ description: null, tagline: null }) },
    })
    const text = wrapper.text()
    expect(text).toContain("Web Search")
    expect(text).not.toContain("Search the web straight from your agent")
  })
})

// @vitest-environment nuxt
import { describe, it, expect, beforeEach } from "vitest"
import { mountSuspended } from "@nuxt/test-utils/runtime"
import ThemeSwitch from "./ThemeSwitch.vue"

describe("ThemeSwitch", () => {
  beforeEach(() => {
    document.cookie = "theme=ivory; path=/"
  })

  it("trigger shows the Sun icon when theme is ivory", async () => {
    const wrapper = await mountSuspended(ThemeSwitch)
    expect(wrapper.find("svg.lucide-sun").exists()).toBe(true)
    expect(wrapper.find("svg.lucide-moon").exists()).toBe(false)
    expect(wrapper.find('svg[data-theme-icon="mono"]').exists()).toBe(false)
  })

  it("trigger shows the Moon icon when theme is dark", async () => {
    document.cookie = "theme=dark; path=/"
    const wrapper = await mountSuspended(ThemeSwitch)
    expect(wrapper.find("svg.lucide-moon").exists()).toBe(true)
    expect(wrapper.find("svg.lucide-sun").exists()).toBe(false)
  })

  it("trigger shows the half-filled contrast disc when theme is mono", async () => {
    document.cookie = "theme=mono; path=/"
    const wrapper = await mountSuspended(ThemeSwitch)
    const monoIcon = wrapper.find('svg[data-theme-icon="mono"]')
    expect(monoIcon.exists()).toBe(true)
    // disc outline + half-filled path
    expect(monoIcon.find("circle").exists()).toBe(true)
    expect(monoIcon.find("path").exists()).toBe(true)
    expect(wrapper.find("svg.lucide-sun").exists()).toBe(false)
    expect(wrapper.find("svg.lucide-moon").exists()).toBe(false)
  })

  it("trigger exposes the Theme aria-label and a title with the current theme", async () => {
    const wrapper = await mountSuspended(ThemeSwitch)
    const trigger = wrapper.find("button")
    expect(trigger.attributes("aria-label")).toBe("Theme")
    expect(trigger.attributes("title")).toContain("Ivory")
  })
})

